const body = $json.body || $json;
const event = body.event || '';
const labels = body.labels || [];
const issueKey = body.issueKey || '';
const summary = body.summary || '';

const actions = [];

// Feature shipped with needs-marketing -> dispatch marketing
if (event === 'feature-shipped' && labels.includes('needs-marketing')) {
  actions.push({ type: 'dispatch', agent: 'marketing', issueKey, prompt: `Create marketing content for shipped feature: ${summary}` });
}

// Feature shipped -> check if release notes needed
if (event === 'feature-shipped' && labels.includes('needs-release-note')) {
  actions.push({ type: 'dispatch', agent: 'product-manager', issueKey, action: 'release-notes' });
}

// Bug resolved -> notify sales if customer-reported
if (event === 'bug-resolved' && labels.includes('customer-reported')) {
  actions.push({ type: 'notify', channel: 'sales', message: `Bug ${issueKey} resolved: ${summary}. Customer can be notified.` });
}

// Feedback classified as bug -> auto-triage
if (event === 'feedback-classified' && labels.includes('Bug')) {
  actions.push({ type: 'dispatch', agent: 'bug-triage', issueKey });
}

if (actions.length === 0) {
  actions.push({ type: 'skip', reason: `No cross-functional action for event=${event} labels=${labels.join(',')}` });
}

return actions.map(a => ({ json: a }));

const action = $json;
const issueKey = action.issueKey || '';
const agent = action.agent || '';
const prompt = action.prompt || '';
const actionType = action.action || '';

const body = {
  issueKey,
  agent,
  workingDir: '{{DEFAULT_WORKING_DIR}}',
  callbackUrl: '{{N8N_PUBLIC_URL}}/webhook/runner/callback'
};

if (prompt) {
  body.description = prompt;
}

if (actionType) {
  body.action = actionType;
}

return [{ json: {
  body,
  idempotencyKey: `cf:${agent}:${issueKey}:${Date.now()}`
} }];

const action = $json;
const channel = action.channel || 'engineering';
const message = action.message || 'Cross-functional notification';

const chatMap = {
  sales: '-5115168416',
  engineering: '-5037701631'
};

const chatId = chatMap[channel] || chatMap.engineering;

return [{ json: { chatId, message } }];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
